import requests

# Mock API endpoint (simulated data)
MODERN_WARFARE_API = "https://api.example.com/callofduty/modernwarfare"

def get_modern_warfare_release_dates():
    try:
        response = requests.get(MODERN_WARFARE_API)
        response.raise_for_status()
        data = response.json()

        # Extract release dates for Modern Warfare sub-series games
        release_dates = {
            game['title']: game['release_date']
            for game in data
            if game['sub_series'] == 'Modern Warfare'
        }
        return release_dates
    except requests.exceptions.RequestException as e:
        return f"Error fetching data: {e}"

# Example usage
if __name__ == "__main__":
    dates = get_modern_warfare_release_dates()
    for title, date in dates.items():
        print(f"{title}: {date}")
